function el(id) {
  const node = document.getElementById(id);
  if (!node) throw new Error(`Missing element #${id}`);
  return node;
}

function safeJsonParse(str, fallback) {
  try {
    return JSON.parse(str);
  } catch {
    return fallback;
  }
}

function isHexString(v) {
  return typeof v === "string" && /^0x[0-9a-fA-F]*$/.test(v);
}

function normalizeAbi(abi) {
  if (Array.isArray(abi)) return abi;
  if (abi && typeof abi === "object" && Array.isArray(abi.abi)) return abi.abi;
  throw new Error("Invalid ABI JSON. Provide an ABI array or an object with .abi");
}

function toBigIntOrUndef(v) {
  if (v === "" || v == null) return undefined;
  if (typeof v === "bigint") return v;
  if (typeof v === "number") return BigInt(v);
  if (typeof v === "string") {
    const s = v.trim();
    if (s === "") return undefined;
    if (/^\d+$/.test(s)) return BigInt(s);
    if (isHexString(s)) return BigInt(s);
  }
  throw new Error(`Invalid integer: ${v}`);
}

function gweiToWeiBigInt(gweiStr) {
  const s = (gweiStr ?? "").trim();
  if (!s) return undefined;
  return ethers.parseUnits(s, "gwei");
}

function ethToWeiBigInt(ethStr) {
  const s = (ethStr ?? "").trim();
  if (!s) return 0n;
  return ethers.parseEther(s);
}

function setText(id, text) {
  el(id).textContent = text ?? "";
}

function appendLog(line) {
  const out = el("log");
  out.textContent += (out.textContent ? "\n" : "") + line;
  out.scrollTop = out.scrollHeight;
}

function clearLog() {
  setText("log", "");
}

function setStatus(text) {
  setText("status", text);
}

function setError(text) {
  setText("error", text);
}

function clearError() {
  setError("");
}

function disableWhile(btn, fn) {
  return async (...args) => {
    const prev = btn.disabled;
    btn.disabled = true;
    try {
      return await fn(...args);
    } finally {
      btn.disabled = prev;
    }
  };
}

