class DApp {
  constructor() {
    this.browserProvider = null;
    this.rpcProvider = null;
    this.provider = null;
    this.signer = null;
    this.contract = null;
    this.contractReadOnly = null;
    this.abi = null;
    this.address = null;
    this.connected = false;
    this.readOnly = false;
  }

  async init() {
    buildUI(document.body);
    this.loadDefaults();
    this.bindEvents();
    await this.refreshNetworkInfo();
  }

  loadDefaults() {
    el("rpcUrl").value = DEFAULTS.rpcUrl;
    el("contractAddress").value = DEFAULTS.contractAddress;
    el("abiJson").value = DEFAULTS.abiJson;
    el("method").value = DEFAULTS.method;
    el("argsJson").value = DEFAULTS.argsJson;
    el("valueEth").value = DEFAULTS.valueEth;
    el("gasLimit").value = DEFAULTS.gasLimit;
    el("maxFeePerGasGwei").value = DEFAULTS.maxFeePerGasGwei;
    el("maxPriorityFeePerGasGwei").value = DEFAULTS.maxPriorityFeePerGasGwei;
    el("nonce").value = DEFAULTS.nonce;
    el("chainId").value = DEFAULTS.chainId ?? "";
  }

  bindEvents() {
    el("btnConnect").onclick = disableWhile(el("btnConnect"), async () => {
      clearError();
      clearLog();
      await this.connectWallet();
    });

    el("btnDisconnect").onclick = async () => {
      clearError();
      await this.disconnect();
    };

    el("btnLoadFromRpc").onclick = disableWhile(el("btnLoadFromRpc"), async () => {
      clearError();
      clearLog();
      await this.useRpcProvider();
    });

    el("btnParseAbi").onclick = () => {
      clearError();
      try {
        this.parseAbi();
        appendLog("ABI parsed successfully.");
      } catch (e) {
        setError(String(e?.message ?? e));
      }
    };

    el("btnListMethods").onclick = () => {
      clearError();
      try {
        this.parseAbi();
        const iface = new ethers.Interface(this.abi);
        const frags = Object.values(iface.fragments).filter((f) => f.type === "function");
        const lines = frags
          .map((f) => {
            const inputs = (f.inputs ?? []).map((i) => `${i.type}${i.name ? " " + i.name : ""}`).join(", ");
            const outputs = (f.outputs ?? []).map((o) => o.type).join(", ");
            const mut = f.stateMutability;
            return `${f.name}(${inputs}) -> (${outputs || "void"}) [${mut}]`;
          })
          .sort();
        appendLog(lines.join("\n") || "(No functions found in ABI)");
      } catch (e) {
        setError(String(e?.message ?? e));
      }
    };

    el("btnClearLog").onclick = () => clearLog();

    el("btnRead").onclick = disableWhile(el("btnRead"), async () => {
      clearError();
      await this.ensureContract();
      await this.readCall();
    });

    el("btnEstimate").onclick = disableWhile(el("btnEstimate"), async () => {
      clearError();
      await this.ensureContract();
      await this.estimateGas();
    });

    el("btnBuildTx").onclick = disableWhile(el("btnBuildTx"), async () => {
      clearError();
      await this.ensureContract();
      await this.buildTx();
    });

    el("btnSend").onclick = disableWhile(el("btnSend"), async () => {
      clearError();
      await this.ensureContract(true);
      await this.sendTx();
    });

    if (window.ethereum) {
      window.ethereum.on?.("accountsChanged", async () => {
        if (!this.connected) return;
        await this.connectWallet(true);
      });
      window.ethereum.on?.("chainChanged", async () => {
        await this.refreshNetworkInfo();
      });
    }
  }

  parseAbi() {
    const abiRaw = el("abiJson").value.trim();
    const parsed = safeJsonParse(abiRaw, null);
    if (!parsed) throw new Error("ABI JSON parse failed.");
    this.abi = normalizeAbi(parsed);
    return this.abi;
  }

  async connectWallet(silent = false) {
    if (!window.ethereum) throw new Error("No injected wallet found (window.ethereum). Install MetaMask or similar.");
    setStatus("Connecting wallet...");
    this.browserProvider = new ethers.BrowserProvider(window.ethereum);

    if (!silent) {
      await this.browserProvider.send("eth_requestAccounts", []);
    }

    this.signer = await this.browserProvider.getSigner();
    this.provider = this.browserProvider;
    this.connected = true;
    this.readOnly = false;

    const addr = await this.signer.getAddress();
    setText("walletAddr", addr);

    await this.refreshNetworkInfo();
    await this.ensureContract(false, true);

    setStatus("Wallet connected.");
    appendLog(`Connected: ${addr}`);
  }

  async disconnect() {
    this.browserProvider = null;
    this.rpcProvider = null;
    this.provider = null;
    this.signer = null;
    this.contract = null;
    this.contractReadOnly = null;
    this.connected = false;
    this.readOnly = false;
    setText("walletAddr", "Not connected");
    setText("networkInfo", "-");
    setStatus("Disconnected.");
  }

  async useRpcProvider() {
    const rpcUrl = el("rpcUrl").value.trim();
    if (!rpcUrl) throw new Error("RPC URL is required for read-only mode.");
    setStatus("Connecting RPC provider...");
    this.rpcProvider = new ethers.JsonRpcProvider(rpcUrl);
    this.provider = this.rpcProvider;
    this.signer = null;
    this.connected = false;
    this.readOnly = true;
    setText("walletAddr", "Read-only (RPC)");
    await this.refreshNetworkInfo();
    await this.ensureContract(false, true);
    setStatus("RPC provider ready (read-only).");
    appendLog(`RPC provider: ${rpcUrl}`);
  }

  async refreshNetworkInfo() {
    try {
      if (!this.provider) {
        setText("networkInfo", "-");
        return;
      }
      const net = await this.provider.getNetwork();
      setText("networkInfo", `${net.name} (chainId=${net.chainId.toString()})`);
    } catch {
      setText("networkInfo", "-");
    }
  }

  async ensureContract(requireSigner = false, forceRecreate = false) {
    const contractAddress = el("contractAddress").value.trim();
    if (!ethers.isAddress(contractAddress)) throw new Error("Invalid contract address.");
    this.address = contractAddress;

    if (!this.abi) this.parseAbi();

    if (!this.provider) {
      if (window.ethereum) {
        this.browserProvider = new ethers.BrowserProvider(window.ethereum);
        this.provider = this.browserProvider;
      } else {
        throw new Error("No provider available. Connect wallet or set RPC URL.");
      }
    }

    if (requireSigner) {
      if (!this.signer) {
        if (this.browserProvider) this.signer = await this.browserProvider.getSigner();
      }
      if (!this.signer) throw new Error("No signer available. Connect wallet to send transactions.");
    }

    if (forceRecreate || !this.contractReadOnly) {
      this.contractReadOnly = new ethers.Contract(this.address, this.abi, this.provider);
    }

    if (requireSigner) {
      if (forceRecreate || !this.contract) {
        this.contract = new ethers.Contract(this.address, this.abi, this.signer);
      }
    } else {
      this.contract = null;
    }
  }

  getUserMethodAndArgs() {
    const method = el("method").value.trim();
    if (!method) throw new Error("Method name is required.");

    const argsRaw = el("argsJson").value.trim();
    const args = argsRaw ? safeJsonParse(argsRaw, null) : [];
    if (args === null || !Array.isArray(args)) throw new Error("Arguments must be a JSON array.");

    return { method, args };
  }

  getTxOverrides() {
    const value = ethToWeiBigInt(el("valueEth").value);
    const gasLimit = toBigIntOrUndef(el("gasLimit").value.trim());
    const maxFeePerGas = gweiToWeiBigInt(el("maxFeePerGasGwei").value);
    const maxPriorityFeePerGas = gweiToWeiBigInt(el("maxPriorityFeePerGasGwei").value);
    const nonce = toBigIntOrUndef(el("nonce").value.trim());
    const chainId = toBigIntOrUndef(el("chainId").value.trim());

    const overrides = {};
    if (value != null) overrides.value = value;
    if (gasLimit != null) overrides.gasLimit = gasLimit;
    if (maxFeePerGas != null) overrides.maxFeePerGas = maxFeePerGas;
    if (maxPriorityFeePerGas != null) overrides.maxPriorityFeePerGas = maxPriorityFeePerGas;
    if (nonce != null) overrides.nonce = nonce;
    if (chainId != null) overrides.chainId = chainId;

    return overrides;
  }

  async readCall() {
    setStatus("Reading (callStatic)...");
    const { method, args } = this.getUserMethodAndArgs();

    const c = this.contractReadOnly;
    if (!c?.[method]) throw new Error(`Method not found on contract: ${method}`);

    const result = await c[method](...args);
    const formatted = this.formatResult(result);

    appendLog(`READ ${method}(${this.formatArgs(args)}) => ${formatted}`);
    setStatus("Read complete.");
  }

  async estimateGas() {
    setStatus("Estimating gas...");
    const { method, args } = this.getUserMethodAndArgs();
    const overrides = this.getTxOverrides();

    const c = this.contractReadOnly;
    if (!c?.[method]) throw new Error(`Method not found on contract: ${method}`);

    const gas = await c[method].estimateGas(...args, overrides);
    appendLog(`ESTIMATE ${method}(${this.formatArgs(args)}) => gasLimit=${gas.toString()}`);
    setStatus("Estimate complete.");
  }

  async buildTx() {
    setStatus("Building transaction...");
    const { method, args } = this.getUserMethodAndArgs();
    const overrides = this.getTxOverrides();

    const iface = new ethers.Interface(this.abi);
    const data = iface.encodeFunctionData(method, args);

    const tx = {
      to: this.address,
      data,
      ...overrides,
    };

    const txJson = this.stringifyTx(tx);
    el("builtTx").value = txJson;

    appendLog(`BUILT TX for ${method}(${this.formatArgs(args)})`);
    appendLog(txJson);
    setStatus("Transaction built.");
  }

  async sendTx() {
    setStatus("Sending transaction...");
    const { method, args } = this.getUserMethodAndArgs();
    const overrides = this.getTxOverrides();

    const c = this.contract;
    if (!c?.[method]) throw new Error(`Method not found on contract: ${method}`);

    const txResponse = await c[method](...args, overrides);
    appendLog(`SENT ${method} => hash=${txResponse.hash}`);

    setStatus("Waiting for confirmation...");
    const receipt = await txResponse.wait();
    appendLog(`CONFIRMED status=${receipt.status} block=${receipt.blockNumber} gasUsed=${receipt.gasUsed?.toString?.() ?? receipt.gasUsed}`);
    setStatus("Transaction confirmed.");
  }

  formatArgs(args) {
    return args
      .map((a) => {
        if (typeof a === "string") return JSON.stringify(a);
        if (typeof a === "bigint") return a.toString();
        return JSON.stringify(a);
      })
      .join(", ");
  }

  formatResult(result) {
    try {
      if (result == null) return String(result);
      if (typeof result === "bigint") return result.toString();
      if (typeof result === "string") return result;
      if (Array.isArray(result)) return JSON.stringify(result, this.jsonReplacer, 2);
      if (typeof result === "object") {
        if (result.toJSON) return JSON.stringify(result.toJSON(), this.jsonReplacer, 2);
        return JSON.stringify(result, this.jsonReplacer, 2);
      }
      return String(result);
    } catch {
      return String(result);
    }
  }

  jsonReplacer(_k, v) {
    if (typeof v === "bigint") return v.toString();
    return v;
  }

  stringifyTx(tx) {
    const normalized = { ...tx };
    for (const k of Object.keys(normalized)) {
      const v = normalized[k];
      if (typeof v === "bigint") normalized[k] = v.toString();
    }
    return JSON.stringify(normalized, null, 2);
  }
}

const app = new DApp();
app.init().catch((e) => {
  const msg = String(e?.message ?? e);
  try {
    setError(msg);
    setStatus("Error");
    appendLog(msg);
  } catch {
    console.error(e);
  }
});